div.t-attf-class:
form-check form-check-inline border rounded p-3 flex-fill
                                                #{not can_50 and 'opacity-50' or ''}
                                                #{form_data.get('withdrawal_type') == '50' and 'border-primary bg-primary bg-opacity-10' or ''}

form-check form-check-inline border rounded p-3 flex-fill
                                                #{not can_75 and 'opacity-50' or ''}
                                                #{form_data.get('withdrawal_type') == '75' and 'border-primary bg-primary bg-opacity-10' or ''}

t.script:
var _elig = {
    '50': '',
    '75': ''
};
function updateMaxAmount(radio) {
    var hint = document.getElementById('max_amount_hint');
    if (hint && _elig[radio.value]) {
        hint.textContent = 'Maximum eligible: ' + _elig[radio.value] + ' JOD';
    }
}
// Run on load to set hint for pre-selected type
document.addEventListener('DOMContentLoaded', function() {
    var checked = document.querySelector('input[name="withdrawal_type"]:checked');
    if (checked) updateMaxAmount(checked);
});

